const results = $input.first().json.results || [];
return results.map(p => ({ json: {
  pageId: p.id,
  caseName: p.properties?.['案名']?.title?.[0]?.plain_text || '(未命名)',
  contract_no: (p.properties?.['案件編號']?.rich_text?.[0]?.plain_text || '').toUpperCase(),
  fbPostUrl: p.properties?.['粉專貼文連結']?.url || ''
}})).filter(x => x.json.contract_no);

const responses = $input.all();
const sources = $('展開結果').all();
return responses.map((resp, i) => {
  const inItem = sources[i]?.json || {};
  const r = resp.json || {};
  const status = Number(r.statusCode ?? r.status ?? 0);
  const body = r.body ?? r;
  let isRemoved = false, reason = '';
  if (status === 200 && body && typeof body === 'object') {
    const items = body.items || body.data || [];
    const total = body.total != null ? Number(body.total) : items.length;
    if (total === 0) { isRemoved = true; reason = 'KEIS 查無此案（已移除）'; }
    else if (items[0] && items[0].is_active === false) { isRemoved = true; reason = 'KEIS is_active=false（已下架）'; }
    else { isRemoved = false; reason = '仍在架上'; }
  } else {
    // KEIS 逾時/非 200/異常 → 不判下架，避免誤刪
    isRemoved = false; reason = `KEIS 暫時無法確認(HTTP ${status})，本次略過`;
  }
  return { json: { ...inItem, isRemoved, reason, detectedAt: new Date().toISOString() } };
});

const j = $json;
const m = (j.fbPostUrl || '').match(/facebook\.com\/(\d+_\d+)/);
return [{ json: { ...j, fbPostId: m ? m[1] : '', hasFbPost: !!(m && m[1]) } }];

const prep = $('備妥刪文').item.json;
const resp = $json || {};
const rb = resp.body ?? resp;
let ok, failed, errMsg = '';
if (!prep.hasFbPost) { ok = true; failed = false; }
else {
  const success = rb === true || rb?.success === true || (typeof rb === 'string' && rb.includes('success'));
  errMsg = rb?.error?.message || '';
  const alreadyGone = /does not exist|Unsupported (get|delete) request|cannot be loaded|Object with ID/i.test(errMsg);
  ok = success || alreadyGone;
  failed = !ok;
}
return [{ json: { ...prep, fbDeleted: prep.hasFbPost && ok, fbDeleteFailed: failed, fbDeleteError: failed ? (errMsg || 'unknown') : '', markRemoved: ok } }];

const checked = $('判斷是否下架').all().map(i => i.json);
const total = checked.length;
const removed = checked.filter(x => x.isRemoved);
const today = new Date().toLocaleDateString('zh-TW', { timeZone: 'Asia/Taipei' });
let outcomes = [];
try { outcomes = $('判定刪除結果').all().map(i => i.json); } catch (e) {}
const byPage = {}; outcomes.forEach(o => byPage[o.pageId] = o);
let text;
if (total === 0) text = `🌅 下架偵測 ${today}\n\n沒有已發布的廣告需要偵測。`;
else if (removed.length === 0) text = `🌅 下架偵測 ${today}\n\n✅ 檢查 ${total} 筆，全部仍在架上。`;
else {
  const lines = removed.map(r => {
    const o = byPage[r.pageId] || {};
    const tag = o.fbDeleteFailed ? `⚠️粉專刪除失敗（${o.fbDeleteError}）→ 狀態未改，請手動刪` : (o.fbDeleted ? '粉專貼文已自動刪除' : '無粉專貼文');
    return `・${r.caseName}（${r.contract_no}）— ${r.reason}；${tag}`;
  }).join('\n');
  const failCount = removed.filter(r => (byPage[r.pageId] || {}).fbDeleteFailed).length;
  text = `🚨 下架偵測 ${today}\n\n檢查 ${total} 筆，${removed.length} 筆已下架：\n\n${lines}` + (failCount ? `\n\n⚠️ ${failCount} 筆粉專刪除失敗，需你手動處理。` : '');
}
return [{ json: { userId: 'Ufab42c56b2eb9b9a9ff18c367b85a6dd', summaryText: text } }];
